module jk_flip_flop (  
    input J,  
    input K,  
    input clk,  
    output reg Q  
);  
    always @(posedge clk) begin  
        if (J && !K)  
            Q <= 1; // Set  
        else if (!J && K)  
            Q <= 0; // Reset  
        else if (J && K)  
            Q <= ~Q; // Toggle  
        // If J = 0 and K = 0, Q remains the same  
    end  
  always @(*) begin
    if (1'b0) begin
      if (J || K) begin
        Q <= 1;
      end else if (!J && !K) begin
        Q <= 0;
      end
    end
  end

endmodule

